import{_ as t,o as p,c as r,ag as s}from"./chunks/framework.ETe_P6d1.js";const e="/kaiping-reports/assets/1.BMrexL8e.png",o="/kaiping-reports/assets/2.BLld6r8X.png",i="/kaiping-reports/assets/3.BahAABKW.png",_="/kaiping-reports/assets/4.DY0hq-5R.png",n="/kaiping-reports/assets/5.CVfwEB0n.png",l="/kaiping-reports/assets/6.BaHr2l-W.png",c="/kaiping-reports/assets/7.BNPw7yjb.png",h="/kaiping-reports/assets/8.BtXFTK-t.png",d="/kaiping-reports/assets/9.DvO5oMMo.png",m="/kaiping-reports/assets/10.Cd81qR_n.png",B=JSON.parse('{"title":"开平立园泮立楼与泮文楼建筑装饰符号与文化表达调研报告","description":"","frontmatter":{},"headers":[],"relativePath":"reports/任梓涵/任梓涵_开平立园泮立楼与泮文楼建筑装饰符号与文化表达调研报告.md.md","filePath":"reports/任梓涵/任梓涵_开平立园泮立楼与泮文楼建筑装饰符号与文化表达调研报告.md.md"}'),g={name:"reports/任梓涵/任梓涵_开平立园泮立楼与泮文楼建筑装饰符号与文化表达调研报告.md.md"};function u(k,a,q,b,f,P){return p(),r("div",null,[...a[0]||(a[0]=[s('<h1 id="开平立园泮立楼与泮文楼建筑装饰符号与文化表达调研报告" tabindex="-1">开平立园泮立楼与泮文楼建筑装饰符号与文化表达调研报告 <a class="header-anchor" href="#开平立园泮立楼与泮文楼建筑装饰符号与文化表达调研报告" aria-label="Permalink to &quot;开平立园泮立楼与泮文楼建筑装饰符号与文化表达调研报告&quot;">​</a></h1><p><strong>作者：调研团队</strong></p><h2 id="一、建筑背景" tabindex="-1">一、建筑背景 <a class="header-anchor" href="#一、建筑背景" aria-label="Permalink to &quot;一、建筑背景&quot;">​</a></h2><p>建筑背景：立园由旅美华侨谢维立先生于1926年至1936年间回乡兴建，历时十年建成，园名取“立树立人”之意。泮立楼与泮文楼是别墅区的核心建筑，建于1926至1931年间。楼名“泮立”取自园主谢维立与其父谢圣泮之名联珠而成，“泮文”则为其兄谢维文与父名之合称，体现了园主不忘父恩的孝道观念与家族伦理。谢维立先生自幼随父赴美经商，在异国他乡积累了财富，也接受了西方文化的洗礼，但骨子里始终保持着对中国传统文化的认同与归属。这种独特的跨文化经历，深刻影响了立园的建筑风格与装饰语言。</p><h2 id="二、调研目的与意义" tabindex="-1">二、调研目的与意义 <a class="header-anchor" href="#二、调研目的与意义" aria-label="Permalink to &quot;二、调研目的与意义&quot;">​</a></h2><p>本次调研的核心目的在于，通过对泮立楼与泮文楼建筑装饰符号的系统采集与分析，揭示近代华侨建筑在“中西融合”表象之下的深层文化逻辑，回答这些装饰符号如何融合中西建筑语言、承载何种文化意涵、表达怎样的身份认同与价值追求等问题。</p><p>从学术意义来看，开平碉楼与村落作为世界文化遗产，现有研究多集中于碉楼的防御功能和聚落形态，对建筑装饰符号的系统性研究相对薄弱。泮立楼与泮文楼装饰体系完整、工艺精湛，是研究华侨建筑装饰文化的理想样本。从现实意义来看，在全球化日益深入的今天，两栋建筑所呈现的“中西融合”经验——不是简单的模仿或拼贴，而是在深刻理解两种文化基础上进行的创造性转化——对于当代跨文化实践具有重要的启示意义。</p><h2 id="三、中西融合特征" tabindex="-1">三、中西融合特征 <a class="header-anchor" href="#三、中西融合特征" aria-label="Permalink to &quot;三、中西融合特征&quot;">​</a></h2><p>泮立楼与泮文楼最显著的建筑特征，在于其“中国殿堂古风”与“欧美别墅情调”的创造性融合。这种融合并非简单的元素拼贴，而是华侨群体在跨文化实践中形成的独特审美表达。</p><p><img src="'+e+'" alt="1"></p><p>在屋顶处理上，两栋建筑的顶部均采用中国古典宫殿式的重檐歇山顶，覆以绿色琉璃瓦，屋脊饰以壮观的龙脊与吻兽，檐角飘逸上扬。这种屋顶形制在中国传统建筑中等级较高，通常用于宫殿、庙宇等重要建筑。园主将其用于私家别墅，既彰显了社会地位与财富积累，也表达了海外华侨对中华文化正统身份的认同与追慕。屋脊上的龙纹装饰以琉璃烧制，龙头昂首向天，龙身蜿蜒起伏。值得注意的是，建筑顶部采用架空方式处理，形成实用的隔热层，这是结合岭南地区炎热气候的适应性改良。符号标注显示，这部分位于建筑顶部，题材为龙纹与吻兽，风格属于中国宫殿式。</p><p><img src="'+o+'" alt="2"></p><p><img src="'+i+'" alt="3"></p><p>与中式屋顶形成鲜明对比的是，楼身主体呈现浓郁的西洋风味。建筑立面采用古希腊科林斯柱式和古罗马柱式支撑结构，柱头饰以精美的茛苕叶纹，比例修长，线条流畅。这些西式柱式不仅是结构构件，更是装饰元素。窗户采用欧美式的拱券窗形制，部分窗洞带有巴洛克风格的山花装饰。这种“中式屋顶加西式楼身”的垂直构图方式，形成强烈的视觉张力，成为侨乡建筑最具标志性的“穿西装戴瓜皮帽”风格特征。符号标注显示，这部分位于建筑外立面整体风格属于折衷主义。</p><p><img src="'+_+'" alt="4"></p><p><img src="'+n+'" alt="5"></p><p>在建筑立面的细部处理上，岭南传统灰塑与西式拱券元素常常并置出现。在拱券窗洞的上方或两侧，往往装饰着以中国传统题材为内容的灰塑作品。灰塑是岭南地区特有的传统建筑装饰工艺，以石灰为主料加入颜料塑形，可塑性强，色彩鲜艳。在泮立楼和泮文楼中，灰塑作品的主题包括人物故事、瑞兽花卉等，它们与西式的拱券、柱式在同一建筑面上共存对话，形成独特的跨文化装饰语法。两种不同文化系统的装饰语言相互映照，既彰显了华侨对西方文化的接受，也表达了他们对本土传统的坚守。</p><p>室内空间的装饰同样呈现出中西混合的特征。地面铺设意大利进口的水磨石瓷砖，色彩鲜艳，图案精美。天花采用东洋式精美木雕，部分区域带有伊斯兰风格的几何图案。每层楼都装置了欧美式的取暖壁炉，悬挂着古意盎然的吊灯。而家具则以酸枝等红木制作的广式家具为主，雕刻着中国传统吉祥图案。这种“西式设备加中式家具”的组合方式，既享受了西方现代物质文明的便利，又保留了中式生活的审美情趣。卫生间内安装了浴缸、抽水马桶和水箱，均为国外进口，这在二十世纪二三十年代的中国乡村极为罕见。</p><p><img src="'+l+'" alt="6"></p><p><img src="'+c+'" alt="7"></p><h2 id="四、雕刻题材" tabindex="-1">四、雕刻题材 <a class="header-anchor" href="#四、雕刻题材" aria-label="Permalink to &quot;四、雕刻题材&quot;">​</a></h2><p>泮立楼与泮文楼内的雕刻作品涵盖灰塑、木雕、壁画等多种工艺门类，题材丰富，寓意深远。这些雕刻不仅是装饰，更是华侨精神世界的视觉化呈现。</p><p>在人物故事题材方面，最具代表性的作品是位于泮立楼外墙的“刘备三顾茅庐”灰塑。这幅作品以彩泥浮雕的形式塑造了刘备、关羽、张飞三人前往隆中请诸葛亮出山的历史场景。这一题材的选择耐人寻味——园主谢维立作为旅美华侨，在异国他乡白手起家，或许在“三顾茅庐”的故事中寄寓了对贤才的渴慕，也隐含了自身“身在异邦、心系故国”的身份认同。另一个重要作品是位于泮立楼大厅的“六国大封相”潮州木雕，采用潮州著名的涂金樟木镂通雕工艺，表现战国时期苏秦佩六国相印的荣耀场景。这一题材的选用，既体现了园主对功成名就的向往，也折射出华侨通过个人奋斗实现阶层跃升的“美国梦”叙事。此外，挹翠亭内顶还有彩绘灰塑作品，描绘蓬莱仙景、明皇月宫等题材，表现了对道教仙境和富贵长生的向往。</p><p><img src="'+h+'" alt="8"></p><p>在几何纹样方面，意大利进口的水磨石地面多采用菱形、方形、多边形等几何拼接图案，带有西方装饰艺术风格的特征，与立园的建造年代完全吻合。而木雕花窗中的几何纹则更多延续了中国传统样式，包括冰裂纹、万字纹、回纹等。</p><h2 id="五、色彩运用" tabindex="-1">五、色彩运用 <a class="header-anchor" href="#五、色彩运用" aria-label="Permalink to &quot;五、色彩运用&quot;">​</a></h2><p>泮立楼与泮文楼的色彩体系呈现出“中西合璧”的视觉特征，既有中国传统建筑色彩的庄重华丽，又有西方现代建筑材料的质感表现。</p><p>在主色调方面，两栋建筑的外立面以明黄色墙面为主色调，屋顶覆以翠绿色琉璃瓦，形成“黄墙绿瓦”的经典配色方案。在中国传统色彩体系中，黄色曾为皇家专用色，绿色琉璃瓦也多用于宫殿、庙宇等高规格建筑。园主选用这一配色方案，体现其对尊贵身份的彰显和对中华正统文化的认同。这种配色方案在侨乡建筑中较为罕见，更凸显了立园的独特地位。</p><p><img src="'+d+'" alt="9"></p><p>在砖材运用方面，建筑的某些部位可观察到青砖和红砖的交替使用。青砖是岭南传统建筑的主要材料，给人以素雅、沉稳的视觉感受；红砖则更多见于西式建筑的拱券、柱式等部位，色彩温暖而热烈。两种砖材的交替使用，丰富了建筑的色彩层次，也隐喻了中西文化的交织——青砖代表本土传统，红砖代表西洋风尚。</p><p>在室内色彩方面，较之外立面更为华丽多元。意大利水磨石地面以红、黄、蓝、白等色彩拼贴出精美图案，潮州木雕以金箔贴饰、金光灿灿，彩绘壁画色彩丰富，酸枝家具的深红色则为空间增添了沉稳的质感。总体而言，室内色彩呈现出“华丽多元”的特征，与外立面的“庄重统一”形成内外有别的色彩策略。</p><p><img src="'+m+'" alt="10"></p><h2 id="六、结论" tabindex="-1">六、结论 <a class="header-anchor" href="#六、结论" aria-label="Permalink to &quot;六、结论&quot;">​</a></h2><p>通过对泮立楼与泮文楼装饰符号的系统调研，可以得出以下结论。第一，两栋建筑在形式语言上呈现出显著的“中西融合”特征，具体表现为“中式屋顶加西式楼身”、“中式灰塑加西式拱券”、“中式家具加西式设备”等多层次的融合方式。这种融合不是随意的拼贴，而是华侨群体跨文化身份的建筑表达。第二，雕刻题材以中国传统文化内容为主体，涵盖人物故事、瑞兽花卉、几何纹样、文字符号等类型，折射出园主对功名成就的向往和对中华文化的认同。第三，色彩运用上以“黄墙绿瓦”为主色调，辅以青砖、红砖、水泥灰等材料，呈现出“外庄重、内华丽”的内外有别特征。第四，从文化意义上看，泮立楼与泮文楼是侨乡文化的典型物质载体，承载着华侨群体“爱国爱乡”的家国情怀和“中西融合”的文化态度。</p><h2 id="七、心得体会与反思" tabindex="-1">七、心得体会与反思 <a class="header-anchor" href="#七、心得体会与反思" aria-label="Permalink to &quot;七、心得体会与反思&quot;">​</a></h2><p>通过此次调研，我深体会到“建筑是刻凝固的历史”这句话的含义。站在泮立楼中，每一处装饰都是园主心迹的投射——中式屋顶寄托着对故土的眷恋，西式柱式记录着异乡的经历，灰塑故事传递着对传统价值的坚守。本次采用的“分类采集+符号标注”方法行之有效，使观察更加聚焦深入。但我也认识到时间有限导致观察不够细致、部分区域无法进入等不足。泮立楼所代表的华侨建筑文化启示我们：在全球化时代，文化融合不是简单的拼贴，而是在深刻理解两种文化基础上的创造性转化。</p>',36)])])}const T=t(g,[["render",u]]);export{B as __pageData,T as default};
